INSERT INTO `vocabularies` VALUES (51,6,'vital','(～にとって)非常に重要な(to, for～)； 生命の','形容詞',2,'normal','low',NULL,NULL,'It is vital that we act quickly.','迅速に行動することが不可欠だ。','It is vital that S + V（仮定法現在）の形で「～が不可欠だ」を表す。',1,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(52,6,'vivid','生き生きとした, 鮮やかな','形容詞',1,'normal','low',NULL,NULL,'She gave a vivid description of the scene.','彼女はその場面を生き生きと描写した。','vivid + 名詞の形で「鮮明な～」を表す。SVO構文。',2,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(53,6,'revive','～を生き返らせる, 生き返る','自動詞/他動詞',1,'normal','low',NULL,NULL,'The doctor managed to revive the patient.','医師はなんとか患者を蘇生させた。','manage to do「なんとか～する」。reviveは他動詞で「～を蘇生させる」。',3,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(54,6,'essential','(～にとって)重要な, 必要不可欠な(to, for～)； 本質的な','形容詞/名詞',2,'normal','low',NULL,NULL,'Sleep is essential for good health.','睡眠は健康に不可欠だ。','S is essential for ～「Sは～に不可欠だ」。SVC構文。',4,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(55,6,'indispensable','(～にとって)重要な, 必要不可欠な(to, for～)','形容詞',2,'hard','low',NULL,NULL,'Water is indispensable to life.','水は生命に不可欠だ。','S is indispensable to ～「Sは～に欠かせない」。SVC構文。',5,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(56,6,'crucial','決定的な, 極めて重要な','形容詞',1,'hard','low',NULL,NULL,'This is a crucial moment in our history.','これは我々の歴史における重大な瞬間だ。','crucial + 名詞で「極めて重要な～」を表す。SVC構文。',6,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(57,6,'significance','重要性','名詞',2,'hard','low',NULL,NULL,'Few people understood the significance of the discovery.','その発見の重要性を理解する人はほとんどいなかった。','the significance of ～「～の重要性」。SVO構文。',7,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(58,6,'consequence','結果, 重要さ','名詞',2,'hard','low',NULL,NULL,'He suffered the consequences of his actions.','彼は自分の行動の結果に苦しんだ。','the consequences of ～「～の結果」。SVO構文。',8,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(59,6,'matter','事柄, 問題； 重要である','名詞/自動詞',2,'hard','low',NULL,NULL,'It doesn\'t matter what other people think.','他人がどう思おうと関係ない。','It doesn\'t matter + what節。matterは自動詞で「重要である」。',9,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(60,6,'count','～を数える； 重要である','自動詞/他動詞/名詞',2,'hard','low',NULL,NULL,'Every vote counts in this election.','この選挙ではすべての票が重要だ。','countは自動詞で「重要である」の意味。SV構文。',10,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(61,6,'make a difference','重要である','自動詞句',2,'hard','low',NULL,NULL,'Small changes can make a difference.','小さな変化が違いを生むことがある。','make a difference「違いを生む、重要である」。SVO構文。',11,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(62,6,'trivial','ささいな, ありふれた','形容詞',2,'hard','low',NULL,NULL,'Don\'t waste time on trivial matters.','些細なことに時間を無駄にするな。','trivial + 名詞で「些細な～」。命令文。',12,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(63,6,'trifle','ささいな事, くだらない事','名詞/自動詞',1,'hard','low',NULL,NULL,'He is not a man to be trifled with.','彼はばかにしてはいけない人物だ。','trifle with ～「～を軽く扱う」。不定詞の形容詞的用法。',13,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(64,6,'common','共通の, よくある, 一般的な, ありふれた','形容詞',2,'hard','low',NULL,NULL,'This disease is common among children.','この病気は子供の間でよく見られる。','S is common among ～「Sは～の間でよく見られる」。SVC構文。',14,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(65,6,'ordinary','普通の, 通常の, ありふれた','形容詞',2,'hard','low',NULL,NULL,'It was just an ordinary day.','それはただの普通の日だった。','ordinary + 名詞で「普通の～」。SVC構文。',15,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(66,6,'familiar','(～に)よく知られた(to～)； (～に)精通している(with～)； 親しい','形容詞',2,'hard','low','family',NULL,'I am familiar with this topic.','私はこのトピックをよく知っている。','be familiar with ～「～をよく知っている」。SVC構文。',16,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(67,6,'emphasize','～を強調する','他動詞',2,'hard','low',NULL,NULL,'She emphasized the importance of education.','彼女は教育の重要性を強調した。','emphasize + 名詞「～を強調する」。SVO構文。',17,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(68,6,'stress','～を強調する； ストレス, 重点, 強調','名詞/他動詞',2,'hard','low',NULL,NULL,'He stressed that teamwork was essential.','彼はチームワークが不可欠だと強調した。','stress that節「～だと強調する」。SVO構文（that節が目的語）。',18,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(69,6,'neglect','～を(うっかり)怠る, ～を無視する','他動詞/名詞',2,'hard','low',NULL,NULL,'He neglected his duties for months.','彼は何か月も自分の職務を怠った。','neglect + 名詞「～を怠る」。SVO構文。',19,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(70,6,'ignore','～を無視する, ～を知らないふりをする','他動詞',2,'hard','low',NULL,NULL,'You should not ignore the warning signs.','警告のサインを無視すべきではない。','ignore + 名詞「～を無視する」。SVO構文。',20,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(71,6,'eminent','著名な','形容詞',1,'hard','low',NULL,NULL,'She is an eminent scholar in the field.','彼女はその分野の著名な学者だ。','eminent + 名詞で「著名な～」。SVC構文。',21,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(72,6,'prominent','目立った； 有名な','形容詞',1,'hard','low',NULL,NULL,'He played a prominent role in the project.','彼はそのプロジェクトで重要な役割を果たした。','prominent + 名詞で「目立った、重要な～」。SVO構文。',22,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(73,6,'primary','第1の, 主要な','形容詞',2,'hard','low','データベースのcolumnに指定するprimary key(主要列)',NULL,'Our primary concern is safety.','私たちの第一の関心事は安全だ。','primary + 名詞で「第一の、主要な～」。SVC構文。',23,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(74,6,'tiny','ちっぽけな','形容詞',2,'normal','low','ドンキーコング64の小さい猿「タイニー」',NULL,'She lives in a tiny apartment.','彼女は小さなアパートに住んでいる。','tiny + 名詞で「とても小さな～」。SV構文（前置詞句を伴う）。',24,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(75,6,'slight','わずかな, 取るに足らない','形容詞',2,'hard','low',NULL,NULL,'There has been a slight improvement.','わずかな改善が見られた。','slight + 名詞で「わずかな～」。SV構文（There構文）。',25,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(76,7,'character','性格, 人格, 特徴, 登場人物, 文字','名詞',2,'hard','low',NULL,NULL,'Honesty is an important part of his character.','正直さは彼の性格の重要な部分だ。','character「性格、人格」。SVC構文。',1,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(77,7,'feature','(目立った)特徴, 顔立ち； ～を特集する, 呼び物にする','名詞/他動詞',2,'hard','low','フューチャー',NULL,'The building features a large garden.','その建物には大きな庭が備わっている。','feature + 名詞「～を特徴として持つ」。SVO構文。',2,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(78,7,'trait','特徴, 特色','名詞',1,'hard','low',NULL,NULL,'Kindness is a desirable trait.','優しさは望ましい特性だ。','trait「特性、特質」。SVC構文。',3,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(79,7,'typical','典型的な, (～)らしい(of～)','形容詞',2,'easy','low',NULL,NULL,'This is typical of his behavior.','これは彼の行動に典型的だ。','be typical of ～「～に典型的である」。SVC構文。',4,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(80,7,'unique','(～に)特有の(to～), 独自の； 唯一の','形容詞',2,'hard','low',NULL,NULL,'Each person has a unique fingerprint.','一人ひとりが独自の指紋を持っている。','unique + 名詞で「独自の、唯一の～」。SVO構文。',5,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(81,7,'peculiar','(～に)特有の(to～)； 風変わりな','形容詞',2,'hard','low',NULL,NULL,'There is something peculiar about this place.','この場所には何か奇妙なところがある。','peculiar「奇妙な、独特の」。There is構文。',6,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(82,7,'particular','特定の, 特別の','形容詞/名詞',2,'hard','low',NULL,NULL,'Is there any particular reason for your visit?','訪問に何か特別な理由がありますか。','particular + 名詞で「特定の、特別な～」。疑問文。',7,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(83,7,'general','全般的な, 一般的な','形容詞/名詞',2,'normal','low',NULL,NULL,'The general public has the right to know.','一般大衆には知る権利がある。','general + 名詞で「一般的な～」。SVO構文。',8,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(84,7,'specify','～を特定する','他動詞',1,'hard','low','スペシフィック',NULL,'Please specify the date and time.','日時を明記してください。','specify + 名詞「～を明記する」。命令文。SVO構文。',9,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(85,7,'distinguish','～を(…と)区別する, 見分ける(from…)','自動詞/他動詞',2,'hard','low',NULL,NULL,'It is hard to distinguish fact from fiction.','事実とフィクションを見分けるのは難しい。','distinguish A from B「AとBを区別する」。It is hard to do構文。',10,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(86,7,'define','～を定義する, 明確にする','他動詞',2,'normal','low',NULL,NULL,'How do you define success?','あなたは成功をどう定義しますか。','define + 名詞「～を定義する」。SVO構文。疑問文。',11,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(87,7,'vague','曖昧な, 漠然とした','形容詞',2,'hard','low',NULL,NULL,'His answer was rather vague.','彼の答えはかなり曖昧だった。','vague「曖昧な」。SVC構文。ratherは程度を表す副詞。',12,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(88,7,'obscure','不明瞭な, ぼやけた； 世に知られていない','形容詞/他動詞',1,'hard','low',NULL,NULL,'The meaning of the text remains obscure.','その文章の意味は不明瞭なままだ。','remain + 形容詞「～のままである」。SVC構文。',13,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(89,7,'ambiguous','曖昧な, どちらともとれる','形容詞',1,'hard','low',NULL,NULL,'The law is ambiguous on this point.','この点について法律は曖昧だ。','S is ambiguous on ～「Sは～に関して曖昧だ」。SVC構文。',14,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(90,7,'obvious','明白な','形容詞',2,'hard','low',NULL,NULL,'It is obvious that he is lying.','彼が嘘をついていることは明白だ。','It is obvious that節「～は明白だ」。形式主語のIt。',15,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(91,7,'evident','明白な','形容詞',2,'normal','low','[ビジネス用語]エビデンス',NULL,'It was evident from her expression that she was upset.','彼女が動揺していることは表情から明らかだった。','It is evident from ～ that節「～から…は明らかだ」。形式主語のIt。',16,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(92,7,'apparent','見たところの, 明白な','形容詞',2,'hard','low',NULL,NULL,'The problem became apparent over time.','問題は時間とともに明らかになった。','become apparent「明らかになる」。SVC構文。',17,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(93,7,'respect','尊敬, 尊重, (in)点, 事項； ～を尊敬する, 尊重する','名詞/他動詞',2,'hard','low',NULL,NULL,'We should respect other people\'s opinions.','我々は他人の意見を尊重すべきだ。','respect + 名詞「～を尊重する」。SVO構文。',18,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(94,7,'aspect','(in)側面, 様相, 点','名詞',2,'hard','low',NULL,NULL,'We need to consider every aspect of the problem.','問題のあらゆる側面を考慮する必要がある。','aspect of ～「～の側面」。SVO構文。',19,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(95,7,'detail','(in)詳細','名詞/他動詞',2,'normal','low',NULL,NULL,'She described the event in great detail.','彼女はその出来事を詳細に説明した。','in detail「詳細に」は副詞句。SVO構文。',20,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(96,7,'precise','正確な','形容詞',2,'hard','low',NULL,NULL,'Can you give me the precise location?','正確な場所を教えてもらえますか。','precise + 名詞で「正確な～」。SVO構文。疑問文。',21,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(97,7,'accurate','正確な','形容詞',2,'hard','low',NULL,NULL,'The report was not entirely accurate.','その報告は完全には正確ではなかった。','accurate「正確な」。SVC構文。',22,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(98,8,'structure','構造, 構成, 骨格','名詞/他動詞',2,'normal','low',NULL,NULL,'The structure of the building is impressive.','その建物の構造は印象的だ。','the structure of ～「～の構造」。SVC構文。',1,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(99,8,'construct','～を建設する, 組み立てる','他動詞/名詞',2,'hard','low',NULL,NULL,'They constructed a bridge over the river.','彼らは川に橋を建設した。','construct + 名詞「～を建設する」。SVO構文。',2,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(100,8,'destroy','～を破壊する, 滅ぼす','他動詞',2,'easy','low',NULL,NULL,'The earthquake destroyed many buildings.','地震が多くの建物を破壊した。','destroy + 名詞「～を破壊する」。SVO構文。',3,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(101,8,'architecture','建築, 建築学','名詞',1,'normal','low',NULL,NULL,'She studied architecture at university.','彼女は大学で建築学を学んだ。','architecture「建築学」。SVO構文。',4,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(102,8,'constitute','～を構成する, 占める； 設立する','他動詞',2,'hard','low',NULL,NULL,'Women constitute about half the population.','女性は人口の約半数を構成している。','constitute + 名詞「～を構成する」。SVO構文。',5,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(103,8,'institute','～(法律・制度)を制定する； 協会, 研究所','名詞/他動詞',1,'hard','low',NULL,NULL,'The government instituted a new policy.','政府は新しい政策を設けた。','institute + 名詞「～を制定する、設ける」。SVO構文。',6,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(104,8,'substitute','～を(…の代わりに)代用する(for…)； 代用品, 代理人','名詞/自動詞/他動詞/形容詞',2,'hard','low',NULL,NULL,'You can substitute honey for sugar.','砂糖の代わりに蜂蜜を使えます。','substitute A for B「BのかわりにAを用いる」。SVO構文。',7,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(105,8,'stable','安定した','形容詞/名詞',2,'hard','low',NULL,NULL,'The patient\'s condition is now stable.','患者の容態は現在安定している。','stable「安定した」。SVC構文。',8,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(106,8,'establish','～を設立する, 確立する','他動詞',2,'normal','low',NULL,NULL,'The company was established in 1990.','その会社は1990年に設立された。','be established「設立される」。受動態。',9,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(107,8,'subject','科目, 主題, 家来, 臣民； 患者, 被験者； (～に)従属している, かかりやすい(to～)','名詞/形容詞/他動詞',2,'hard','low',NULL,NULL,'The plan is subject to change.','その計画は変更される可能性がある。','be subject to ～「～を受けやすい、～の対象である」。SVC構文。',10,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(108,8,'subdue','～を征服する, 支配する, 抑える','他動詞',1,'hard','low',NULL,NULL,'The police managed to subdue the suspect.','警察はなんとか容疑者を取り押さえた。','subdue + 名詞「～を制圧する」。SVO構文。',11,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(109,8,'submit','（～に)服従する, 身を任せる(to～)； ～を服従させる, を提出する','自動詞/他動詞',2,'hard','low',NULL,NULL,'She submitted her report on time.','彼女は時間通りにレポートを提出した。','submit + 名詞「～を提出する」。SVO構文。',12,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(110,8,'submission','服従, 提出','名詞',1,'hard','low',NULL,NULL,'The deadline for submission is next Friday.','提出期限は来週の金曜日だ。','submission「提出」。SVC構文。',13,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(111,8,'fundamental','根本的な, 基礎的な, 重要な','形容詞/名詞',2,'hard','low',NULL,NULL,'Education is a fundamental right.','教育は基本的な権利だ。','fundamental + 名詞で「基本的な～」。SVC構文。',14,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(112,8,'fund','資金, 基金','名詞/他動詞',1,'hard','low',NULL,NULL,'The project is funded by the government.','そのプロジェクトは政府によって資金提供されている。','be funded by ～「～によって資金提供される」。受動態。',15,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(113,8,'found','～を設立する','他動詞',1,'hard','low',NULL,NULL,'The university was founded in 1850.','その大学は1850年に設立された。','be founded「設立される」。受動態。foundは「設立する」の意味。',16,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(114,8,'foundation','基盤, 基礎, 土台','名詞',1,'hard','low',NULL,NULL,'The foundation of the building is very strong.','その建物の基礎は非常に強固だ。','the foundation of ～「～の基礎」。SVC構文。',17,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(115,8,'profound','深い, 深遠な','形容詞',2,'hard','low',NULL,NULL,'His words had a profound effect on me.','彼の言葉は私に深い影響を与えた。','profound + 名詞で「深い、深遠な～」。SVO構文。',18,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(116,8,'base','土台、基礎','名詞/他動詞/形容詞',2,'normal','low',NULL,NULL,'The company is based in Tokyo.','その会社は東京に本拠地を置いている。','be based in ～「～に本拠地を置く」。受動態。',19,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(117,8,'basis','基礎','名詞',1,'normal','low',NULL,NULL,'There is no basis for this claim.','この主張には根拠がない。','the basis for ～「～の根拠」。There is構文。',20,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(118,8,'ground','運動場, 地面, 根拠, 理由','名詞/他動詞',2,'hard','low',NULL,NULL,'He was arrested on the grounds of fraud.','彼は詐欺の理由で逮捕された。','on the grounds of ～「～の理由で」。受動態。',21,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(119,8,'superficial','うわべの','形容詞',2,'hard','low',NULL,NULL,'His knowledge of the subject is superficial.','そのテーマに関する彼の知識は表面的だ。','superficial「表面的な」。SVC構文。',22,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(120,8,'shallow','浅い； 浅はかな, うわべの','形容詞',1,'hard','low',NULL,NULL,'The river is very shallow here.','ここでは川はとても浅い。','shallow「浅い」。SVC構文。',23,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(121,8,'superb','すばらしい, 見事な','形容詞',1,'hard','low',NULL,NULL,'The performance was absolutely superb.','その演技は実に素晴らしかった。','superb「素晴らしい」。SVC構文。',24,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(122,8,'supervise','～を監視する, 指揮する','他動詞',1,'hard','low',NULL,NULL,'She supervises a team of twenty people.','彼女は20人のチームを監督している。','supervise + 名詞「～を監督する」。SVO構文。',25,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(123,8,'superstition','迷信','名詞',2,'hard','low',NULL,NULL,'Many superstitions have no scientific basis.','多くの迷信には科学的根拠がない。','superstition「迷信」。SVO構文。',26,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(124,8,'core','中心, 核心； (果物の)芯','名詞/形容詞',1,'normal','low',NULL,NULL,'Trust is the core of any relationship.','信頼はあらゆる関係の核心だ。','the core of ～「～の核心」。SVC構文。',27,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(125,8,'surface','表面, 表層','名詞/自動詞',2,'normal','low',NULL,NULL,'A whale surfaced near the boat.','クジラがボートの近くで水面に浮上した。','surface は自動詞で「浮上する」。SV構文。',28,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(126,8,'internal','内面の, 内側の','形容詞',2,'hard','low',NULL,NULL,'This is an internal matter of the company.','これは会社の内部問題だ。','internal + 名詞で「内部の～」。SVC構文。',29,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(127,8,'external','外側の','形容詞',2,'hard','low',NULL,NULL,'We need to consider external factors as well.','外部要因も考慮する必要がある。','external + 名詞で「外部の～」。SVO構文。',30,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(128,8,'concentrate','(～に)集中する(on～)； ～を(…に)集中させる(on…)','自動詞/他動詞',2,'hard','low',NULL,NULL,'I can\'t concentrate on my work.','仕事に集中できない。','concentrate on ～「～に集中する」。SV構文（前置詞句を伴う）。',31,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(129,8,'focus','(～に)集中する, 重点を置く(on～)； 焦点','自動詞/他動詞',2,'normal','low',NULL,NULL,'Let\'s focus on the main issue.','主要な問題に焦点を当てよう。','focus on ～「～に焦点を当てる」。SV構文（前置詞句を伴う）。',32,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(130,8,'compose','～を構成する； 作曲・作文する','他動詞',2,'hard','low',NULL,NULL,'The committee is composed of ten members.','委員会は10人のメンバーで構成されている。','be composed of ～「～で構成されている」。受動態。',33,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(131,8,'consist','(～から)成る(of～), (～の中に)ある, 存在する(in～)','自動詞',2,'hard','low',NULL,NULL,'The team consists of five members.','そのチームは5人のメンバーで構成されている。','consist of ～「～から成る」。自動詞。SV構文（前置詞句を伴う）。',34,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(132,8,'organize','～を組織する','他動詞',2,'normal','low',NULL,NULL,'She organized a charity event.','彼女は慈善イベントを企画した。','organize + 名詞「～を企画する」。SVO構文。',35,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(133,8,'element','要素, 元素','名詞',2,'normal','low',NULL,NULL,'Patience is a key element of success.','忍耐は成功の重要な要素だ。','element of ～「～の要素」。SVC構文。',36,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(134,8,'component','構成要素, 部分','名詞/形容詞',1,'hard','low',NULL,NULL,'Each component plays a vital role.','各部品が重要な役割を果たしている。','component「構成要素、部品」。SVO構文。',37,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(135,8,'complex','複雑な, 複合の','形容詞/名詞',2,'hard','low',NULL,NULL,'The problem is more complex than we thought.','問題は我々が思っていたよりも複雑だ。','complex「複雑な」。比較級構文。SVC構文。',38,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(136,8,'complicated','複雑な','形容詞',2,'easy','low',NULL,NULL,'The instructions were too complicated to follow.','その指示は複雑すぎて従えなかった。','too ～ to do「～すぎて…できない」。SVC構文。',39,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(137,9,'reveal','～を明らかにする, 暴露する','他動詞',2,'hard','low',NULL,NULL,'The investigation revealed the truth.','調査が真実を明らかにした。','reveal + 名詞「～を明らかにする」。SVO構文。',1,'2026-06-30 13:46:58','2026-06-30 13:46:58'),(138,9,'conceal','～を隠す','他動詞',2,'normal','low','(化粧品の)コンシーラー',NULL,'He tried to conceal his identity.','彼は自分の正体を隠そうとした。','conceal + 名詞「～を隠す」。SVO構文。try to do。',2,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(139,9,'expose','～をさらす','他動詞',2,'hard','low',NULL,NULL,'The journalist exposed the corruption.','そのジャーナリストは汚職を暴露した。','expose + 名詞「～を暴露する」。SVO構文。',3,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(140,9,'impose','～を(…に)課す, 押しつける(on[upon]…)','自動詞/他動詞',2,'hard','low',NULL,NULL,'The government imposed a new tax on imports.','政府は輸入品に新しい税を課した。','impose A on B「AをBに課す」。SVO構文。',4,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(141,9,'divide','～を分割する','自動詞/他動詞/名詞',2,'normal','low','ディビジョン',NULL,'The river divides the city into two parts.','川がその都市を二つに分けている。','divide A into B「AをBに分ける」。SVO構文。',5,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(142,9,'diffuse','～をまき散らす, 分散する； 拡散する','自動詞/他動詞/形容詞',1,'normal','low','ディフューザー',NULL,'The scent diffused throughout the room.','香りが部屋中に広がった。','diffuse「広がる」。自動詞。SV構文。',6,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(143,9,'scatter','～をまき散らす','自動詞/他動詞',1,'normal','low',NULL,NULL,'The wind scattered the leaves.','風が葉を散らした。','scatter + 名詞「～を散らす」。SVO構文。',7,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(144,9,'spread','広がる, 普及する','自動詞/他動詞/名詞',2,'normal','low',NULL,NULL,'The news spread quickly.','ニュースは急速に広まった。','spread「広まる」。自動詞。SV構文。',8,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(145,9,'bend','～を曲げる','自動詞/他動詞/名詞',2,'hard','low',NULL,NULL,'She bent down to pick up the coin.','彼女はコインを拾うためにかがんだ。','bend down「かがむ」。自動詞。to doは目的を表す不定詞の副詞的用法。',9,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(146,9,'incline','～を傾ける, (…したい)気持ちにさせる(to do)','自動詞/他動詞/名詞',2,'hard','low','⇔decline 衰退、～を断る',NULL,'I am inclined to agree with you.','あなたに同意する傾向がある。','be inclined to do「～する傾向がある」。SVC構文。',10,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(147,9,'lean','(～に)寄りかかる, もたれる(on[against]～)','自動詞/形容詞',2,'hard','low',NULL,NULL,'He leaned against the wall.','彼は壁に寄りかかった。','lean against ～「～に寄りかかる」。自動詞。SV構文（前置詞句を伴う）。',11,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(148,9,'erect','～を直立させる, 建てる； 直立した','他動詞/形容詞',1,'normal','low','ワールドダウンタウン「ビンビン エレクト」',NULL,'They erected a monument in the park.','彼らは公園に記念碑を建てた。','erect + 名詞「～を建てる」。SVO構文。',12,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(149,9,'emit','～を放出する, 排出する','他動詞',2,'hard','low',NULL,NULL,'The factory emits a large amount of carbon dioxide.','その工場は大量の二酸化炭素を排出している。','emit + 名詞「～を排出する」。SVO構文。',13,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(150,9,'absorb','～を吸収する','他動詞',2,'hard','low',NULL,NULL,'The sponge absorbs water quickly.','スポンジは素早く水を吸収する。','absorb + 名詞「～を吸収する」。SVO構文。',14,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(151,9,'attract','～を惹(引)き付ける, 魅了する','他動詞',2,'hard','low',NULL,NULL,'The museum attracts thousands of visitors every year.','その博物館は毎年何千人もの来場者を引きつける。','attract + 名詞「～を引きつける」。SVO構文。',15,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(152,9,'extract','～を抜き出す, 抽出する','他動詞/名詞',1,'hard','low',NULL,NULL,'They extracted oil from the ground.','彼らは地中から石油を採掘した。','extract A from B「AをBから取り出す」。SVO構文。',16,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(153,9,'aim','目標, 目的； (～を)狙う, 目標とする(at～)','自動詞/他動詞/名詞',2,'normal','low',NULL,NULL,'We aim to finish the project by March.','私たちは3月までにプロジェクトを終えることを目指している。','aim to do「～することを目指す」。SV構文（不定詞を伴う）。',17,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(154,9,'penetrate','～を貫通する, ～に浸透する； 貫通する（through～）','自動詞/他動詞',2,'normal','low',NULL,NULL,'The bullet penetrated the wall.','弾丸が壁を貫通した。','penetrate + 名詞「～を貫通する」。SVO構文。',18,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(155,9,'thrust','～を(ぐいっと)押し付ける, 突っ込む, 突き刺す','自動詞/他動詞/名詞',1,'hard','low',NULL,NULL,'He thrust the letter into my hand.','彼は手紙を私の手に押しつけた。','thrust A into B「AをBに突きつける」。SVO構文。',19,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(156,9,'insert','～を挿入する','他動詞',1,'hard','low',NULL,NULL,'Please insert your card into the machine.','カードを機械に挿入してください。','insert A into B「AをBに挿入する」。命令文。SVO構文。',20,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(157,9,'grasp','～を掴む, 握る； 理解する','自動詞/他動詞/名詞',2,'hard','low',NULL,NULL,'She grasped the rope tightly.','彼女はロープをしっかりとつかんだ。','grasp + 名詞「～をつかむ」。SVO構文。',21,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(158,9,'grab','～を掴む','自動詞/他動詞/名詞',2,'hard','low',NULL,NULL,'He grabbed my arm suddenly.','彼は突然私の腕をつかんだ。','grab + 名詞「～をつかむ」。SVO構文。',22,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(159,9,'seize','～を掴む, (感情などが)を襲う； 押収する','他動詞',2,'hard','low',NULL,NULL,'The police seized a large quantity of drugs.','警察は大量の薬物を押収した。','seize + 名詞「～を押収する、つかむ」。SVO構文。',23,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(160,9,'drag','～を引きずる','自動詞/他動詞/名詞',2,'normal','low',NULL,NULL,'He dragged the heavy box across the floor.','彼は重い箱を床の上で引きずった。','drag + 名詞「～を引きずる」。SVO構文。',24,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(161,9,'cling','（～に)しがみつく, 固執する(to～)','自動詞',2,'hard','low',NULL,NULL,'The child clung to her mother.','その子供は母親にしがみついた。','cling to ～「～にしがみつく」。自動詞。SV構文（前置詞句を伴う）。',25,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(162,9,'stick','棒； (～に)くっつく, 固執する(to～)','自動詞/他動詞/名詞',2,'normal','low',NULL,NULL,'The stamp won\'t stick to the envelope.','切手が封筒に貼りつかない。','stick to ～「～にくっつく」。自動詞。SV構文（前置詞句を伴う）。',26,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(163,9,'attach','～をくっつける； 愛着を持たせる','自動詞/他動詞',2,'hard','low',NULL,NULL,'Please attach a photo to the application form.','申込書に写真を添付してください。','attach A to B「AをBに添付する」。命令文。SVO構文。',27,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(164,9,'imitate','～を真似る','他動詞',2,'normal','low',NULL,NULL,'Children often imitate their parents\' behavior.','子供はしばしば親の行動を真似る。','imitate + 名詞「～を真似る」。SVO構文。',28,'2026-06-30 13:46:59','2026-06-30 13:46:59'),(165,9,'fold','～を折り畳む','自動詞/他動詞/名詞',2,'hard','low',NULL,NULL,'She folded the letter and put it in the envelope.','彼女は手紙を折って封筒に入れた。','fold + 名詞「～を折りたたむ」。SVO構文。',29,'20